//! # mosaic-emit-react — Emitting TypeScript React functional components.
//!
//! This crate is the React backend for the Mosaic compiler. It implements
//! [`MosaicRenderer`] and is driven by [`MosaicVM`]. The output is a `.tsx`
//! string containing a complete TypeScript React functional component.
//!
//! ## Output file structure
//!
//! ```tsx
//! // Auto-generated by mosaic-emit-react. Do not edit.
//! import React from "react";
//!
//! interface ProfileCardProps {
//!   avatarUrl: string;
//!   displayName: string;
//! }
//!
//! export function ProfileCard({ avatarUrl, displayName }: ProfileCardProps) {
//!   return (
//!     <div style={{ display: 'flex', flexDirection: 'column' }}>
//!       <span>{displayName}</span>
//!     </div>
//!   );
//! }
//! ```
//!
//! ## Architecture: stack-based JSX generation
//!
//! The renderer maintains a **stack of string buffers**, one per open node.
//! - `begin_node` pushes a new buffer.
//! - `end_node` pops it, wraps it in a JSX element string, and appends it
//!   to the parent buffer.
//!
//! This handles arbitrary nesting without lookahead.
//!
//! ## Primitive node → HTML element mapping
//!
//! | Mosaic  | HTML element                                        |
//! |---------|-----------------------------------------------------|
//! | Box     | `<div>`                                             |
//! | Column  | `<div style={{ display:'flex', flexDirection:'column' }}>` |
//! | Row     | `<div style={{ display:'flex', flexDirection:'row' }}>` |
//! | Text    | `<span>` (or `<h2>` if `a11y-role: heading`)        |
//! | Image   | `<img … />`                                         |
//! | Spacer  | `<div style={{ flex: 1 }}>`                         |
//! | Scroll  | `<div style={{ overflow: 'auto' }}>`                |
//! | Divider | `<hr />`                                            |
//! | Stack   | `<div style={{ position: 'relative' }}>`            |
//! | Icon    | `<span className="icon">` (simplified)              |

use mosaic_vm::{EmitResult, MosaicRenderer, ResolvedProperty, ResolvedValue};
use mosaic_analyzer::{MosaicSlot, MosaicType};

// ===========================================================================
// Stack frames
// ===========================================================================

/// Represents one level on the node stack.
struct NodeFrame {
    tag: String,
    is_primitive: bool,
    props: Vec<ResolvedProperty>,
    /// JSX lines accumulated for this node's children.
    lines: Vec<String>,
    /// Whether this node is self-closing (e.g. <img />).
    self_closing: bool,
    /// Content text (for Text nodes where `content` is set directly).
    content: Option<String>,
}

// ===========================================================================
// ReactRenderer
// ===========================================================================

/// The React backend for the Mosaic compiler.
///
/// Implement `MosaicRenderer`, accumulate JSX, and call `emit()` to finalize.
///
/// # Example
///
/// ```no_run
/// use mosaic_emit_react::ReactRenderer;
/// use mosaic_vm::MosaicVM;
/// use mosaic_analyzer::analyze;
///
/// let file = analyze("component Label { slot text: text; Text { content: @text; } }").unwrap();
/// let vm = MosaicVM::new(file);
/// let result = vm.run(ReactRenderer::new()).unwrap();
/// println!("{}", result.output);
/// ```
pub struct ReactRenderer {
    component_name: String,
    slots: Vec<MosaicSlot>,
    /// Stack of open node frames.
    stack: Vec<NodeFrame>,
    /// Lines accumulated at the component (root) level.
    root_lines: Vec<String>,
}

impl ReactRenderer {
    /// Create a new `ReactRenderer`.
    pub fn new() -> Self {
        Self {
            component_name: String::new(),
            slots: Vec::new(),
            stack: Vec::new(),
            root_lines: Vec::new(),
        }
    }

    // -----------------------------------------------------------------------
    // JSX generation helpers
    // -----------------------------------------------------------------------

    /// Map a primitive Mosaic tag to a JSX opening tag string (e.g. `<div>`).
    fn primitive_open_tag(tag: &str, props: &[ResolvedProperty]) -> (String, bool) {
        // Returns (opening_tag_string, self_closing).
        let style = build_style_string(props);
        let class = extract_class(props);
        let extra_attrs = build_extra_attrs(props);

        match tag {
            "Box" | "Stack" => {
                let s = if tag == "Stack" {
                    "position: 'relative'".to_string()
                } else {
                    String::new()
                };
                let combined = combine_styles(&s, &style);
                (format_div(&combined, &class, &extra_attrs), false)
            }
            "Column" => {
                let base = "display: 'flex', flexDirection: 'column'";
                let combined = combine_styles(base, &style);
                (format_div(&combined, &class, &extra_attrs), false)
            }
            "Row" => {
                let base = "display: 'flex', flexDirection: 'row'";
                let combined = combine_styles(base, &style);
                (format_div(&combined, &class, &extra_attrs), false)
            }
            "Text" => {
                // Use <h2> if a11y-role is "heading".
                let elem = if extra_attrs.contains("heading") { "h2" } else { "span" };
                let combined = style.clone();
                let class_attr = if class.is_empty() {
                    String::new()
                } else {
                    format!(" className=\"{class}\"")
                };
                let style_attr = if combined.is_empty() {
                    String::new()
                } else {
                    format!(" style={{{{ {combined} }}}}")
                };
                (format!("<{elem}{class_attr}{style_attr}>"), false)
            }
            "Image" => {
                let src = props
                    .iter()
                    .find(|p| p.name == "source")
                    .map(|p| resolved_value_to_jsx(&p.value))
                    .unwrap_or_else(|| "\"\"".to_string());
                let alt = props
                    .iter()
                    .find(|p| p.name == "a11y-label")
                    .map(|p| resolved_value_to_jsx(&p.value))
                    .unwrap_or_else(|| "\"\"".to_string());
                (format!("<img src={src} alt={alt} />"), true)
            }
            "Spacer" => {
                let base = "flex: 1";
                let combined = combine_styles(base, &style);
                (format_div(&combined, &class, &extra_attrs), false)
            }
            "Scroll" => {
                let base = "overflow: 'auto'";
                let combined = combine_styles(base, &style);
                (format_div(&combined, &class, &extra_attrs), false)
            }
            "Divider" => (format!("<hr />"), true),
            "Icon" => {
                let class_attr = if class.is_empty() {
                    " className=\"icon\"".to_string()
                } else {
                    format!(" className=\"icon {class}\"")
                };
                (format!("<span{class_attr}>"), false)
            }
            // Unknown primitive — fall back to div.
            _ => (format_div(&style, &class, &extra_attrs), false),
        }
    }

    /// Map a component type tag to a JSX element string.
    fn component_open_tag(tag: &str, props: &[ResolvedProperty]) -> String {
        // Emit props as JSX attributes.
        let attrs: Vec<String> = props
            .iter()
            .map(|p| {
                let camel = to_camel_case(&p.name);
                let val = resolved_value_to_jsx(&p.value);
                format!("{camel}={val}")
            })
            .collect();
        if attrs.is_empty() {
            format!("<{tag}>")
        } else {
            format!("<{tag} {}>", attrs.join(" "))
        }
    }

    /// Flush the top-of-stack frame and append its JSX to the parent frame.
    fn flush_frame(&mut self) {
        if let Some(frame) = self.stack.pop() {
            let jsx = if frame.self_closing {
                frame.tag.clone() // already formatted as self-closing
            } else {
                let close_tag = if frame.is_primitive {
                    // Determine the close tag from the Mosaic tag.
                    close_tag_for_primitive(&frame.tag)
                } else {
                    format!("</{}>", frame.tag)
                };

                let open = if frame.is_primitive {
                    let (ot, _) = Self::primitive_open_tag(&frame.tag, &frame.props);
                    ot
                } else {
                    Self::component_open_tag(&frame.tag, &frame.props)
                };

                // Content: either direct text content or child lines.
                let inner = if let Some(text) = &frame.content {
                    text.clone()
                } else {
                    frame.lines.join("\n")
                };

                format!("{open}{inner}{close_tag}")
            };

            // Append to parent (or root_lines if stack is now empty).
            if let Some(parent) = self.stack.last_mut() {
                parent.lines.push(jsx);
            } else {
                self.root_lines.push(jsx);
            }
        }
    }

    /// Generate the props interface for the component.
    fn generate_props_interface(&self) -> String {
        if self.slots.is_empty() {
            return format!("interface {}Props {{}}", self.component_name);
        }
        let mut lines = Vec::new();
        lines.push(format!("interface {}Props {{", self.component_name));
        for slot in &self.slots {
            let ts_type = mosaic_type_to_ts(&slot.slot_type);
            let optional = if slot.required { "" } else { "?" };
            let camel = to_camel_case(&slot.name);
            lines.push(format!("  {camel}{optional}: {ts_type};"));
        }
        lines.push("}".to_string());
        lines.join("\n")
    }
}

impl Default for ReactRenderer {
    fn default() -> Self {
        Self::new()
    }
}

impl MosaicRenderer for ReactRenderer {
    fn begin_component(&mut self, name: &str, slots: &[MosaicSlot]) {
        self.component_name = name.to_string();
        self.slots = slots.to_vec();
    }

    fn end_component(&mut self) {
        // Nothing to do — root_lines already has the JSX.
    }

    fn begin_node(&mut self, tag: &str, is_primitive: bool, props: &[ResolvedProperty]) {
        // Check if it's a self-closing primitive.
        let (open_str, self_closing) = if is_primitive {
            Self::primitive_open_tag(tag, props)
        } else {
            (Self::component_open_tag(tag, props), false)
        };

        // Extract content for Text nodes.
        let content = if tag == "Text" && is_primitive {
            props
                .iter()
                .find(|p| p.name == "content")
                .map(|p| resolved_value_to_jsx_text(&p.value))
        } else {
            None
        };

        if self_closing {
            // Push a frame that will be immediately popped as self-closing.
            self.stack.push(NodeFrame {
                tag: open_str, // store the full self-closing tag
                is_primitive,
                props: props.to_vec(),
                lines: Vec::new(),
                self_closing: true,
                content: None,
            });
        } else {
            self.stack.push(NodeFrame {
                tag: tag.to_string(),
                is_primitive,
                props: props.to_vec(),
                lines: Vec::new(),
                self_closing: false,
                content,
            });
        }
    }

    fn end_node(&mut self, _tag: &str) {
        self.flush_frame();
    }

    fn render_slot_child(&mut self, slot_name: &str, _slot_type: &MosaicType) {
        let jsx = format!("{{{}}}", to_camel_case(slot_name));
        if let Some(frame) = self.stack.last_mut() {
            frame.lines.push(jsx);
        } else {
            self.root_lines.push(jsx);
        }
    }

    fn begin_when(&mut self, slot_name: &str) {
        let camel = to_camel_case(slot_name);
        let jsx_open = format!("{{{camel} && (");
        if let Some(frame) = self.stack.last_mut() {
            frame.lines.push(jsx_open);
        } else {
            self.root_lines.push(jsx_open);
        }
    }

    fn end_when(&mut self) {
        let jsx_close = ")}}".to_string();
        if let Some(frame) = self.stack.last_mut() {
            frame.lines.push(jsx_close);
        } else {
            self.root_lines.push(jsx_close);
        }
    }

    fn begin_each(&mut self, slot_name: &str, item_name: &str, _element_type: &MosaicType) {
        let camel = to_camel_case(slot_name);
        let jsx_open = format!(
            "{{{camel}.map(({item_name}, _idx) => ("
        );
        if let Some(frame) = self.stack.last_mut() {
            frame.lines.push(jsx_open);
        } else {
            self.root_lines.push(jsx_open);
        }
    }

    fn end_each(&mut self) {
        let jsx_close = "))}}".to_string();
        if let Some(frame) = self.stack.last_mut() {
            frame.lines.push(jsx_close);
        } else {
            self.root_lines.push(jsx_close);
        }
    }

    fn emit(self) -> EmitResult {
        // Build params.
        let params = if self.slots.is_empty() {
            String::new()
        } else {
            let params: Vec<String> = self
                .slots
                .iter()
                .map(|s| to_camel_case(&s.name))
                .collect();
            format!(
                "{{ {} }}: {}Props",
                params.join(", "),
                self.component_name
            )
        };

        let props_iface = self.generate_props_interface();
        let jsx_body = self.root_lines.join("\n");

        let output = format!(
            "// Auto-generated by mosaic-emit-react. Do not edit.\nimport React from \"react\";\n\n{props_iface}\n\nexport function {name}({params}) {{\n  return (\n{body}\n  );\n}}",
            name = self.component_name,
            body = indent_lines(&jsx_body, 4),
        );

        EmitResult {
            output,
            component_name: self.component_name,
        }
    }
}

// ===========================================================================
// Helpers
// ===========================================================================

/// Convert `kebab-case` to `camelCase`.
fn to_camel_case(s: &str) -> String {
    let mut result = String::new();
    let mut cap_next = false;
    for ch in s.chars() {
        if ch == '-' {
            cap_next = true;
        } else if cap_next {
            result.push(ch.to_ascii_uppercase());
            cap_next = false;
        } else {
            result.push(ch);
        }
    }
    result
}

/// Convert a `MosaicType` to a TypeScript type string.
fn mosaic_type_to_ts(t: &MosaicType) -> String {
    match t {
        MosaicType::Primitive(p) => match p.as_str() {
            "text" => "string".into(),
            "number" => "number".into(),
            "bool" => "boolean".into(),
            "image" => "string".into(),
            "color" => "string".into(),
            "node" => "React.ReactNode".into(),
            other => other.to_string(),
        },
        MosaicType::Component(name) => format!("React.ReactNode /* {name} */"),
        MosaicType::List(elem) => format!("Array<{}>", mosaic_type_to_ts(elem)),
    }
}

/// Convert a `ResolvedValue` to a JSX attribute value expression string.
fn resolved_value_to_jsx(v: &ResolvedValue) -> String {
    match v {
        ResolvedValue::String(s) => format!("\"{s}\""),
        ResolvedValue::Number(n) => format!("{{{n}}}"),
        ResolvedValue::Dimension(n, unit) => {
            let px = match unit.as_str() {
                "dp" | "sp" => format!("\"{n}px\""),
                "%" => format!("\"{n}%\""),
                _ => format!("\"{n}{unit}\""),
            };
            px
        }
        ResolvedValue::Color(r, g, b, a) => {
            if *a == 255 {
                format!("\"rgb({r}, {g}, {b})\"")
            } else {
                let alpha = *a as f64 / 255.0;
                format!("\"rgba({r}, {g}, {b}, {alpha:.3})\"")
            }
        }
        ResolvedValue::Bool(b) => format!("{{{b}}}"),
        ResolvedValue::SlotRef { name, .. } => format!("{{{}}}", to_camel_case(name)),
        ResolvedValue::Enum { namespace, member } => format!("\"{namespace}-{member}\""),
    }
}

/// Convert a `ResolvedValue` to an inline JSX child expression (for Text content).
fn resolved_value_to_jsx_text(v: &ResolvedValue) -> String {
    match v {
        ResolvedValue::String(s) => s.clone(),
        ResolvedValue::SlotRef { name, .. } => format!("{{{}}}", to_camel_case(name)),
        other => resolved_value_to_jsx(other),
    }
}

/// Build an inline style string from properties that map to CSS.
fn build_style_string(props: &[ResolvedProperty]) -> String {
    let skip = ["content", "source", "a11y-label", "a11y-role", "a11y-hidden", "style"];
    let entries: Vec<String> = props
        .iter()
        .filter(|p| !skip.contains(&p.name.as_str()))
        .map(|p| {
            let camel = to_camel_case(&p.name);
            let val = match &p.value {
                ResolvedValue::String(s) => format!("'{s}'"),
                ResolvedValue::Number(n) => n.to_string(),
                ResolvedValue::Dimension(n, unit) => match unit.as_str() {
                    "dp" | "sp" => format!("'{n}px'"),
                    "%" => format!("'{n}%'"),
                    _ => format!("'{n}{unit}'"),
                },
                ResolvedValue::Color(r, g, b, a) => {
                    if *a == 255 {
                        format!("'rgb({r}, {g}, {b})'")
                    } else {
                        let alpha = *a as f64 / 255.0;
                        format!("'rgba({r}, {g}, {b}, {alpha:.3})'")
                    }
                }
                ResolvedValue::Bool(b) => b.to_string(),
                ResolvedValue::SlotRef { name, .. } => to_camel_case(name),
                ResolvedValue::Enum { namespace, member } => format!("'{namespace}-{member}'"),
            };
            format!("{camel}: {val}")
        })
        .collect();
    entries.join(", ")
}

/// Extract a className from a `style:` property if present.
fn extract_class(props: &[ResolvedProperty]) -> String {
    props
        .iter()
        .find(|p| p.name == "style")
        .map(|p| match &p.value {
            ResolvedValue::Enum { namespace, member } => {
                format!("mosaic-{namespace}-{member}")
            }
            ResolvedValue::String(s) => s.clone(),
            _ => String::new(),
        })
        .unwrap_or_default()
}

/// Extract extra HTML attributes (a11y, etc.) for use in special handling.
fn build_extra_attrs(props: &[ResolvedProperty]) -> String {
    let mut attrs = Vec::new();
    for p in props {
        match p.name.as_str() {
            "a11y-label" => {
                let val = resolved_value_to_jsx(&p.value);
                attrs.push(format!("aria-label={val}"));
            }
            "a11y-role" => {
                let val = resolved_value_to_jsx(&p.value);
                attrs.push(format!("role={val}"));
                // Stash the raw value for heading detection.
                if let ResolvedValue::String(s) = &p.value {
                    attrs.push(s.clone()); // sentinel for heading detection
                }
            }
            "a11y-hidden" => {
                let val = resolved_value_to_jsx(&p.value);
                attrs.push(format!("aria-hidden={val}"));
            }
            _ => {}
        }
    }
    attrs.join(" ")
}

/// Combine a base style string with additional styles.
fn combine_styles(base: &str, extra: &str) -> String {
    match (base.is_empty(), extra.is_empty()) {
        (true, true) => String::new(),
        (true, false) => extra.to_string(),
        (false, true) => base.to_string(),
        (false, false) => format!("{base}, {extra}"),
    }
}

/// Format a `<div>` with optional style and className.
fn format_div(style: &str, class: &str, extra: &str) -> String {
    let mut parts = Vec::new();
    if !style.is_empty() {
        parts.push(format!("style={{{{ {style} }}}}"));
    }
    if !class.is_empty() {
        parts.push(format!("className=\"{class}\""));
    }
    // Include extra attributes (a11y, role, etc.) but not the heading sentinel.
    let clean_extra: Vec<&str> = extra
        .split_whitespace()
        .filter(|s| s.starts_with("aria-") || s.starts_with("role"))
        .collect();
    if !clean_extra.is_empty() {
        parts.push(clean_extra.join(" "));
    }
    if parts.is_empty() {
        "<div>".to_string()
    } else {
        format!("<div {}>", parts.join(" "))
    }
}

/// Get the closing tag for a primitive element.
fn close_tag_for_primitive(tag: &str) -> String {
    match tag {
        "Box" | "Column" | "Row" | "Stack" | "Spacer" | "Scroll" => "</div>".to_string(),
        "Text" => "</span>".to_string(),
        "Icon" => "</span>".to_string(),
        "Image" | "Divider" => String::new(), // self-closing
        _ => "</div>".to_string(),
    }
}

/// Indent every line by `spaces` spaces.
fn indent_lines(s: &str, spaces: usize) -> String {
    let pad = " ".repeat(spaces);
    s.lines()
        .map(|line| {
            if line.trim().is_empty() {
                line.to_string()
            } else {
                format!("{pad}{line}")
            }
        })
        .collect::<Vec<_>>()
        .join("\n")
}

// ===========================================================================
// Tests
// ===========================================================================

#[cfg(test)]
mod tests {
    use super::*;
    use mosaic_vm::MosaicVM;
    use mosaic_analyzer::analyze;

    fn emit(src: &str) -> String {
        let file = analyze(src).unwrap();
        let vm = MosaicVM::new(file);
        vm.run(ReactRenderer::new()).unwrap().output
    }

    // -----------------------------------------------------------------------
    // Test 1: Output contains React import
    // -----------------------------------------------------------------------

    #[test]
    fn test_react_import() {
        let out = emit(r#"component X { Box { } }"#);
        assert!(out.contains("import React from \"react\""), "Missing React import");
    }

    // -----------------------------------------------------------------------
    // Test 2: Export function with component name
    // -----------------------------------------------------------------------

    #[test]
    fn test_export_function() {
        let out = emit(r#"component ProfileCard { Box { } }"#);
        assert!(out.contains("export function ProfileCard"), "Missing export function");
    }

    // -----------------------------------------------------------------------
    // Test 3: Props interface is generated
    // -----------------------------------------------------------------------

    #[test]
    fn test_props_interface() {
        // Note: slot name must not be a keyword — use "title" not "text".
        let out = emit(r#"component Label { slot title: text; Text { content: @title; } }"#);
        assert!(out.contains("interface LabelProps"), "Missing props interface");
        assert!(out.contains("title"), "Missing slot in interface");
    }

    // -----------------------------------------------------------------------
    // Test 4: Column → flex column div
    // -----------------------------------------------------------------------

    #[test]
    fn test_column_renders_flex_column() {
        let out = emit(r#"component X { Column { } }"#);
        assert!(
            out.contains("flexDirection: 'column'") || out.contains("flexDirection:'column'"),
            "Expected flexDirection: 'column' in output: {out}"
        );
    }

    // -----------------------------------------------------------------------
    // Test 5: Row → flex row div
    // -----------------------------------------------------------------------

    #[test]
    fn test_row_renders_flex_row() {
        let out = emit(r#"component X { Row { } }"#);
        assert!(
            out.contains("flexDirection: 'row'") || out.contains("flexDirection:'row'"),
            "Expected flexDirection: 'row' in output: {out}"
        );
    }

    // -----------------------------------------------------------------------
    // Test 6: Text → span element
    // -----------------------------------------------------------------------

    #[test]
    fn test_text_renders_span() {
        let out = emit(r#"component X { Text { content: "Hello"; } }"#);
        assert!(out.contains("<span"), "Expected <span in output: {out}");
    }

    // -----------------------------------------------------------------------
    // Test 7: Slot reference generates camelCase variable
    // -----------------------------------------------------------------------

    #[test]
    fn test_slot_ref_camel_case() {
        let out = emit(r#"component Label { slot display-name: text; Text { content: @display-name; } }"#);
        assert!(
            out.contains("displayName"),
            "Expected camelCase slot ref in output: {out}"
        );
    }

    // -----------------------------------------------------------------------
    // Test 8: when block generates conditional JSX
    // -----------------------------------------------------------------------

    #[test]
    fn test_when_block_conditional() {
        let out = emit(r#"
          component Cond {
            slot show: bool;
            Column {
              when @show {
                Text { content: "Hi"; }
              }
            }
          }
        "#);
        assert!(
            out.contains("show &&") || out.contains("show&&"),
            "Expected conditional in output: {out}"
        );
    }

    // -----------------------------------------------------------------------
    // Test 9: each block generates .map()
    // -----------------------------------------------------------------------
    // NOTE: Uses list<text> which requires a grammar fix in the Rust parser.

    #[test]
    #[ignore = "Rust GrammarParser resolves 'list' as KEYWORD before list_type"]
    fn test_each_block_map() {
        let out = emit(r#"
          component List {
            slot items: list<text>;
            Column {
              each @items as item {
                Text { content: @item; }
              }
            }
          }
        "#);
        assert!(out.contains(".map("), "Expected .map() in output: {out}");
    }

    // -----------------------------------------------------------------------
    // Test 10: No-slot component has empty params
    // -----------------------------------------------------------------------

    #[test]
    fn test_no_slot_empty_params() {
        let out = emit(r#"component Empty { Box { } }"#);
        // The function should have no props parameter or an empty one.
        assert!(out.contains("export function Empty"), "Missing function");
    }
}
